import Link from "next/link";
import styles from "./contact.module.css";
import Image from "react-bootstrap/Image";
import Container from "react-bootstrap/Container";
import Row from "react-bootstrap/Row";
import Col from "react-bootstrap/Col";

function Contact() {
  return (
    <div className={styles.container}>
      <Container>
        <Col md={10} className={styles.icons}>
          <Row>
            <Col md={2}>
              <Row className={styles.icon}>
                <Image src="/mail.png" fluid />
              </Row>
            </Col>

            <Col md={2}>
              <Row className={styles.icon}>
                <Image src="/mail.png" fluid />
              </Row>
            </Col>

            <Col md={2}>
              <Image className={styles.icon} src="/insta.png" fluid />
            </Col>

            <Col md={2}>
              <Image className={styles.icon} src="/github.png" fluid />
            </Col>

            <Col md={2}>
              <Image className={styles.icon} src="/linkedin.png" fluid />
            </Col>
          </Row>
        </Col>
      </Container>
    </div>
  );
}

export default Contact;
